import { memo } from "react";
import { useTranslation } from "react-i18next";
import { useNavigate } from "react-router-dom";
import { ArrowRight, Heart, MessageCircle, Image as ImageIcon, Play } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Skeleton } from "@/components/ui/skeleton";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { useCommunityPosts } from "@/hooks/useCommunityPosts";

const LoadingSkeleton = memo(() => (
  <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
    {Array.from({ length: 4 }).map((_, i) => (
      <Card key={i} className="overflow-hidden">
        <Skeleton className="aspect-[4/3] w-full" />
        <div className="p-4 space-y-2">
          <Skeleton className="h-4 w-full" />
          <Skeleton className="h-3 w-2/3" />
        </div>
      </Card>
    ))}
  </div>
));
LoadingSkeleton.displayName = "CommunityPostsSkeleton";

const HomeCommunityPostsSection = memo(() => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { data: posts, isLoading } = useCommunityPosts({
    status: "approved",
    sortBy: "latest",
    limit: 6,
  });

  // Prioritize posts with images, then fill with others
  const recentPosts = (() => {
    const all = posts || [];
    const withImages = all.filter((p) => p.image_urls?.length > 0);
    const withVideo = all.filter((p) => !p.image_urls?.length && p.video_url);
    const rest = all.filter((p) => !p.image_urls?.length && !p.video_url);
    return [...withImages, ...withVideo, ...rest].slice(0, 4);
  })();

  if (!isLoading && recentPosts.length === 0) return null;

  return (
    <section className="py-8 sm:py-12 px-4">
      <div className="container mx-auto max-w-7xl">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-xl sm:text-2xl font-bold text-foreground">
            {t("home.communityPosts.title")}
          </h2>
        </div>

        {isLoading ? (
          <LoadingSkeleton />
        ) : (
          <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
            {recentPosts.map((post) => {
              const firstImage = post.image_urls?.[0];
              return (
                <Card
                  key={post.id}
                  className="group cursor-pointer overflow-hidden hover:shadow-lg transition-all duration-300 border-border/50 bg-card rounded-xl"
                  onClick={() => navigate(`/community/post/${post.id}`)}
                >
                  {firstImage ? (
                    <div className="relative aspect-[4/3] overflow-hidden bg-muted">
                      <img
                        src={firstImage}
                        alt=""
                        className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
                        loading="lazy"
                      />
                    </div>
                  ) : post.video_url ? (
                    <div className="relative aspect-[4/3] overflow-hidden bg-muted">
                      <video
                        src={post.video_url}
                        className="w-full h-full object-cover"
                        muted
                        preload="metadata"
                      />
                      <div className="absolute inset-0 flex items-center justify-center bg-black/20">
                        <div className="w-10 h-10 rounded-full bg-background/80 flex items-center justify-center">
                          <Play className="w-5 h-5 text-foreground fill-foreground" />
                        </div>
                      </div>
                    </div>
                  ) : (
                    <div className="relative aspect-[4/3] overflow-hidden bg-gradient-to-br from-primary/10 to-primary/5 flex items-center justify-center">
                      <ImageIcon className="w-12 h-12 text-primary/30" />
                    </div>
                  )}
                  <div className="p-4 space-y-3">
                    <p className="text-sm text-foreground line-clamp-2 leading-relaxed">
                      {post.content}
                    </p>
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-2">
                        <Avatar className="h-6 w-6">
                          <AvatarImage src={post.author?.avatar_url || ""} />
                          <AvatarFallback className="text-xs">
                            {(post.author?.display_name || "U")[0]}
                          </AvatarFallback>
                        </Avatar>
                        <span className="text-xs text-muted-foreground truncate max-w-[100px]">
                          {post.author?.display_name || t("common.anonymous")}
                        </span>
                      </div>
                      <div className="flex items-center gap-3 text-xs text-muted-foreground">
                        <span className="flex items-center gap-1">
                          <Heart className="w-3 h-3" />
                          {post.likes_count || 0}
                        </span>
                        <span className="flex items-center gap-1">
                          <MessageCircle className="w-3 h-3" />
                          {post.comments_count || 0}
                        </span>
                      </div>
                    </div>
                  </div>
                </Card>
              );
            })}
          </div>
        )}

        {!isLoading && recentPosts.length > 0 && (
          <div className="flex justify-center mt-6">
            <Button variant="outline" size="lg" className="gap-2" onClick={() => navigate("/community")}>
              {t("home.communityPosts.viewAll")}
              <ArrowRight className="w-4 h-4" />
            </Button>
          </div>
        )}
      </div>
    </section>
  );
});
HomeCommunityPostsSection.displayName = "HomeCommunityPostsSection";

export default HomeCommunityPostsSection;
